# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
import contextlib

def check_permission(user, filename):
    conn = sqlite3.connect('permissions.db')
    cursor = conn.cursor()
    cursor.execute("SELECT access_level FROM users WHERE username=?", (user,))
    access_level = cursor.fetchone()[0]

    cursor.execute("SELECT access_level FROM file_permissions WHERE filename=? AND access_level <= ?", (filename, access_level))
    result = cursor.fetchone()

    conn.close()

    return result is not None

@contextlib.contextmanager
def open_file(filename):
    try:
        file = open(filename, 'r')
        yield file
    finally:
        file.close()

def get_file_contents(user, filename):
    if check_permission(user, filename):
        with open_file(filename) as f:
            return f.read()
    else:
        raise PermissionError('User does not have permission to read the file.')